     // tornadoActief; de LED-override + de verplichte verplaatsing lopen daarop. Eén-shot: opgeruimd bij de controle.
     const ring = (global.get("palenActief") || global.get("paaltjesLijst") || []).slice().sort((a,b)=>a-b);
     const Nr = ring.length;
     const buur = (u,dd) => { const i = ring.indexOf(u); if (i<0 || Nr<1) return null; return ring[((i+dd)%Nr+Nr)%Nr]; };
     let torns = [];
     for (const c of doelwit) { const a = buur(c,-1), b = buur(c,1); torns.push({ center: c, randen: [a,b].filter(x=>x!=null && x!==c) }); }
     global.set("tornadoActief", torns);
     global.set("paalLedForceRebuild", true);
     tornadoNu = true;
  }
  else if (g.type === "tempo") {
     // Spel-tempo: schaalt de reactietijd van volgende events. Sneller -0.1 (min 0.6), trager +0.1 (max 1.3).
     let f = global.get("spelTempoFactor"); if (f == null) f = 1;
     if (g.richting === "sneller") f = Math.max(0.6, Math.round((f - 0.1)*10)/10);
     else if (g.richting === "trager") f = Math.min(1.3, Math.round((f + 0.1)*10)/10);
     global.set("spelTempoFactor", f);
  }
  else if (g.type === "bom") {
     // Bomaanslag: waarschuwing tijdens de reactietijd (rode tik-LED 13 + zoemer-piep 3) op de doel-uren.
     // De ontploffing + schade volgt bij de controle (Verifieer beweging). Vaste uren via het doelwit.
     for (const u of doelUren()) { commandos.push({ payload: { paal: u, actie: 13 } }); commandos.push({ payload: { paal: u, actie: 3 } }); }
  }
  else if (g.type === "identiteitscrisis") {
     // Schuif de luisternamen een alfabetische stap door (cyclisch) over de actieve spelers.
     const _loc = global.get("spelerLocaties") || {};
     const _gp = global.get("gespauzeerdePlayers") || {};
     const _namen = Object.keys(_loc).filter(n => !_gp[n]).sort((a,b)=>a.localeCompare(b,"nl-BE"));
     let _lm = {};
     for (let i = 0; i < _namen.length; i++) _lm[_namen[i]] = _namen[(i + 1) % _namen.length];
     global.set("luisterNaam", _lm);
     const _rondes = (event && event.duratie != null) ? rolDuratie(event.duratie) : 10;
     we.push(maakEffect({ effect: "identiteitscrisis", naam: "Identiteitscrisis" }, _rondes));
  }
  else if (g.type === "tijdreizen") {
     // Tijdreizen (wereld): achteruit in de tijd wordt toegestaan (niet bestraft) zolang de toestand loopt.
     global.set("tijdreizenActief", true);
     const _rondes = (event && event.duratie != null) ? rolDuratie(event.duratie) : 10;
     we.push(maakEffect({ effect: "tijdreizen", naam: "Tijdreizen" }, _rondes));
  }
  else if (g.type === "max_per_uur") {
     // Max per uur (item 5): tijdelijk plafond X (4-8, = afroepgetal); vlaggenlijst leeg starten.
     const _he = global.get("pofHuidigEvent") || {};
     let _X = Number(_he.getalWaarde); if (!(_X >= 4 && _X <= 8)) _X = 4 + Math.floor(Math.random() * 5);
     global.set("maxPerUur", _X);
     global.set("geenWinstVolgende", {});
     const _rondesM = (event && event.duratie != null) ? rolDuratie(event.duratie) : 12;
     we.push(maakEffect({ effect: "max_per_uur", naam: "Max " + _X + "/uur" }, _rondesM));
  }
  else if (g.type === "polonaise") {
     // Polonaise (item 6): duurt 10 VERPLAATSINGS-events; eigen teller (niet-verouderend effect, in Verifieer beweging afgeteld).
     global.set("polonaiseActief", true);
     global.set("polonaiseTeller", 10);
     we.push(maakEffect({ effect: "polonaise", naam: "Polonaise" }, 999));
  }
  else if (g.type === "etenstijd") {
     // doelwit = de schaapjes (kleur-groep). De WOLF is een underdog: hij komt uit de LAAGSTE 5 van het
     // globale klassement (globaleStats.totaalUren, oplopend), buiten de schapengroep. Binnen die bodem-5
     // wint de speler met de beste aura (laagste auraValsspeel); gelijkspel -> willekeurig.
     const _loc = global.get("spelerLocaties") || {};
     const _gp = global.get("gespauzeerdePlayers") || {};
     const _glob = global.get("globaleStats") || {};
     const sheepSet = new Set(doelwit);
     let kand = Object.keys(_loc).filter(n => !_gp[n] && !sheepSet.has(n));
     if (!kand.length) kand = Object.keys(_loc).filter(n => !_gp[n]);
     // Bodem-5 van het globale klassement; gelijkspel op plek 5 telt volledig mee.
     const _gescoord = kand.map(n => ({ n: n, u: (_glob[n] || {}).totaalUren || 0 })).sort((a, b) => a.u - b.u);
     const _drempel = (_gescoord.length > 5) ? _gescoord[4].u : Infinity;
     kand = _gescoord.filter(x => x.u <= _drempel).map(x => x.n);
     let minA = Infinity; for (const n of kand) minA = Math.min(minA, (stats[n] || {}).auraValsspeel || 0);
     const goed = kand.filter(n => ((stats[n] || {}).auraValsspeel || 0) === minA);
     const wolf = goed.length ? goed[Math.floor(Math.random() * goed.length)] : null;
     const schapen = (doelwit || []).filter(n => n !== wolf);
     const over = (event && event.duratie != null) ? rolDuratie(event.duratie) : 15;
     global.set("etenstijd", { wolf: wolf, schapen: schapen, gevangen: [], over: over });
     we.push(maakEffect({ effect: "etenstijd", naam: "Etenstijd (wolf: " + (wolf || "?") + ")" }, over));
  }
  else if (g.type === "tweeling") {
     // doelwit = 2 spelers. Koppel ze als tweeling (max 4 paren, niemand dubbel). Het paar telt als 1
     // niet-verouderend wereldeffect (instId) zodat de max-engine het meetelt en het in de tabel staat.
     let tw = global.get("tweelingen") || [];
     const inTw = new Set(); for (const p of tw) { inTw.add(p.a); inTw.add(p.b); }
     const vrij = (doelwit || []).filter(n => !inTw.has(n));
     if (tw.length < 4 && vrij.length >= 2) {
        const a = vrij[0], b = vrij[1];
        tw.push({ a: a, b: b, inst: instId });
        global.set("tweelingen", tw);
        we.push(maakEffect({ effect: "tweeling", naam: "Tweeling: " + a + " & " + b }, 9999));
     }
  }
  else if (g.type === "onmiddellijke_dood") { doodNu = true; }
  else if (g.type === "geen") { /* geen neveneffect */ }
  else node.warn("Onbekend gevolg-type: " + g.type);
}
global.set("spelerStats",stats); global.set("bordStaat",bord); global.set("spelerEffecten",se); global.set("wereldEffecten",we);

// Start de reactietijd (zichtbaar afgeteld door de Engine tick). events_sneller halveert.
let reactie = event.reactietijd_s || 10;
if (event.categorie === "toestand" && !event.reactieVast) { const _rt = Number(global.get("reactieToestand")); if (_rt > 0) reactie = _rt; }
if (we.some(e => e.effect === "events_sneller")) reactie = Math.max(1, Math.round(reactie/2));
const _tempo = global.get("tempoFactor"); if (_tempo && _tempo > 0) reactie = Math.max(1, Math.round(reactie * _tempo));
const _spelTempo = global.get("spelTempoFactor") || 1; reactie = Math.max(1, Math.round(reactie * _spelTempo));
// G1: sensing-vloer -- de reactietijd mag nooit onder de settle-latentie van de locatiebepaling
// zakken, anders worden fysiek correcte zetten bestraft (TE WEINIG / late hop -> BEWOOG).
// Settle ~= (minSamples + switchSamples) scans op de nieuwe paal + half mediaan-venster.
const _lpG1 = global.get("locParams") || {};
const _sdG1 = global.get("scanDuurPerPaal") || {};
let _scanMsG1 = 1000; for (const _k in _sdG1) { const _v = Number(_sdG1[_k]); if (_v > _scanMsG1) _scanMsG1 = _v; }
const _minReactie = Math.ceil((((_lpG1.minSamples ?? 2) + (_lpG1.switchSamples ?? 2)) * _scanMsG1 + (_lpG1.vensterMs ?? 6000) / 2) / 1000);
if (reactie < _minReactie) { reactie = _minReactie; node.warn("Reactietijd geklemd op sensing-vloer: " + _minReactie + "s (G1)"); }
// In manueel-modus wachten we op de Controle-knop i.p.v. automatisch af te tellen.
if (global.get("pofManueel") === true) {
    global.set("pofFase", "wacht_controle");
    global.set("pofTeller", 0);
} else {
    global.set("pofFase", "reactie");
    global.set("pofTeller", reactie);
}

return [commandos, (nukeNu || tornadoNu) ? {} : null, doodNu ? { start: true } : null];

// Route een {paal,actie[,toon]}-commando naar de master die dat paal-bereik bezit.
// De bereiken MOETEN exact overeenkomen met de firmware (platformio.ini), de slave-master-keuze en de
// bridge (paal_naar_topic): master1 = palen 1-8, master2 = 9-16, master3 = 17-24.
const p = msg.payload && msg.payload.paal;
const m = (p >= 17) ? 3 : (p >= 9) ? 2 : 1;
msg.topic = "commando/master" + m;
return msg;

// Tel alle blijvende effecten een ronde af; verwijder afgelopen effecten.
// out1: chain -> Kies doelwit | out2: trigger -> Bouw effecten-tabel | out3: "audio afgelopen" -> audio/afspelen
const _events = global.get("pofEvents") || [];
const _evById = {}; for (const _e of _events) _evById[_e.id] = _e;
let _verviel = new Set();      // event-ids waarvan deze ronde een effect verviel
let _idCrisisWeg = false;      // identiteitscrisis verliep -> luisternamen terug naar normaal
let _tijdreizenWeg = false;    // tijdreizen verliep -> achteruit lopen weer bestraft
let _etenstijdWeg = false;     // etenstijd verliep -> wolf/schapen opruimen
let _maxPerUurWeg = false;    // max-per-uur verliep -> plafond + vlaggen weg
function veroud(arr) {
    const out = [];
    for (const e of (arr || [])) {
        if (e.effect === "medicijn") { out.push(e); continue; }
        if (e.effect === "tweeling") { out.push(e); continue; }   // tweeling blijft tot dood/spel-einde
        if (e.effect === "polonaise") { out.push(e); continue; }   // polonaise telt in verplaatsings-events (Verifieer), niet in rondes
        const ne = Object.assign({}, e, { resterendeRondes: e.resterendeRondes - 1 });
        if (ne.resterendeRondes > 0) { out.push(ne); }
        else { if (e.bron) _verviel.add(e.bron); if (e.effect === "identiteitscrisis") _idCrisisWeg = true; if (e.effect === "tijdreizen") _tijdreizenWeg = true; if (e.effect === "etenstijd") _etenstijdWeg = true; if (e.effect === "max_per_uur") _maxPerUurWeg = true; }
    }
    return out;
}

let bord = global.get("bordStaat") || {};
for (const uur in bord) {
    bord[uur].effecten = veroud(bord[uur].effecten);
    if (!bord[uur].effecten.length) delete bord[uur];
}
global.set("bordStaat", bord);

let se = global.get("spelerEffecten") || {};
for (const naam in se) {
    se[naam] = veroud(se[naam]);
    if (!se[naam].length) delete se[naam];
}
global.set("spelerEffecten", se);

global.set("wereldEffecten", veroud(global.get("wereldEffecten")));

if (_idCrisisWeg) global.set("luisterNaam", {});   // crisis voorbij -> namen terug normaal
if (_tijdreizenWeg) global.set("tijdreizenActief", false);   // tijdreizen voorbij -> achteruit weer verboden
// ET4: etenstijd loopt af -> elk schaap dat NOOIT gevangen werd, overleefde de jacht en krijgt
// +5 levensuren. De wolf houdt zijn buit. Bij Stop (resetPartij) nult etenstijd zonder bonus.
if (_etenstijdWeg) {
    const _et = global.get("etenstijd");
    if (_et && _et.schapen && _et.schapen.length) {
        const _gev = new Set(_et.gevangen || []);
        const _locE = global.get("spelerLocaties") || {};
        const _gpE = global.get("gespauzeerdePlayers") || {};
        let _st = global.get("spelerStats") || {};
        const _overlevers = [];
        for (const _sch of _et.schapen) {
            if (_gev.has(_sch) || _locE[_sch] == null || _gpE[_sch] === true) continue;
            let _s = _st[_sch] || {}; if (_s.totaalUren === undefined) _s.totaalUren = 0;
            _s.totaalUren += 5; _st[_sch] = _s; _overlevers.push(_sch);
        }
        if (_overlevers.length) { global.set("spelerStats", _st); node.warn("Etenstijd voorbij: +5 uur voor " + _overlevers.join(", ")); }
    }
    global.set("etenstijd", null);                            // etenstijd voorbij -> wolf is voldaan
}
if (_maxPerUurWeg) { global.set("maxPerUur", null); global.set("geenWinstVolgende", {}); }   // max/uur voorbij -> plafond + vlaggen weg

// "Audio afgelopen": per vervallen event met een audioAfgelopen-cue (dedup), net voor het volgende event.
let _afSeg = [];
for (const _bron of _verviel) { const _ev = _evById[_bron]; if (_ev && _ev.audioAfgelopen) _afSeg.push("events/afgelopen/" + _ev.audioAfgelopen); }
const _afAudio = _afSeg.length ? { payload: { fase: "afgelopen", segments: _afSeg, prioriteit: "normaal" } } : null;

return [msg, { payload: "rebuild" }, _afAudio];

// Plat de drie effect-registers tot tabelrijen voor de Live Radar.
let rijen = [];
const bord = global.get("bordStaat") || {};
for (const uur in bord) {
    for (const e of bord[uur].effecten) {
        rijen.push({ Niveau: "uur", Doel: "Paal " + uur, Effect: e.naam, "Rondes resterend": e.resterendeRondes });
    }
}
const se = global.get("spelerEffecten") || {};
for (const naam in se) {
    for (const e of se[naam]) {
        rijen.push({ Niveau: "speler", Doel: naam, Effect: e.naam, "Rondes resterend": e.resterendeRondes });
    }
}
for (const e of (global.get("wereldEffecten") || [])) {
    rijen.push({ Niveau: "wereld", Doel: "-", Effect: e.naam, "Rondes resterend": e.resterendeRondes });
}
if (!rijen.length) {
    rijen = [{ Niveau: "-", Doel: "-", Effect: "geen actieve effecten", "Rondes resterend": "-" }];
}
msg.payload = rijen;
return msg;

// Sync de toestand-LEDs en publiceer de toestanden/portalen voor de simulator.
// out1 -> pof/toestanden | out2 -> pof/portalen | out3 -> commando/master1 (LED per paal)
const bord = global.get("bordStaat") || {};

// 1) Toestanden-lijst: per actief uur-effect een rij (voor het sim-"Toestanden"-paneel).
const toestanden = [];
for (const u in bord) {
    for (const e of (bord[u].effecten || [])) {
        toestanden.push({ uur: parseInt(u, 10), effect: e.effect, naam: e.naam, resterendeRondes: e.resterendeRondes });
    }
}

// 2) Portaal-paren (voor de paarse verbindingslijn in de simulator).
const seen = {};
const paren = [];
for (const u in bord) {
    for (const e of (bord[u].effecten || [])) {
        if (e.effect !== "portaal") continue;
        const a = parseInt(u, 10);
        const b = e.data && e.data.partner;
        if (b == null) continue;
        for (const pb of (Array.isArray(b) ? b : [b])) {
            const key = a < pb ? a + "-" + pb : pb + "-" + a;
            if (seen[key]) continue;
            seen[key] = true;
            paren.push({ palen: [a, pb] });
        }
    }
}

// 3) LED per paal volgt rechtstreeks uit de actieve toestand: portaal -> paars (1),
// happy_hour -> goud (2), anders uit (0). Stuur enkel bij wijziging; zo gaan verlopen
// of gestopte toestanden vanzelf weer uit (fixt de "stale" paarse palen).
const ACTIE = { portaal: 1, happy_hour: 2, medicijn: 4, tijdbom: 13 };
const palenRing = (global.get("palenActief") || global.get("paaltjesLijst") || []).slice();
const nukeActief = global.get("nukeActief") === true;
const oogstMoment = global.get("middernachtOogst") === true;
const mnPaal = global.get("middernachtPaal") || (palenRing.length ? Math.max.apply(null, palenRing) : null);
const gewenst = {};
if (oogstMoment) {
    // Dramatische oogst-animatie over de HELE ring (actie 11).
    for (const u of palenRing) gewenst[u] = 11;
} else if (nukeActief) {
    // NUKE-ring: hele arena nucleair (actie 8) BEHALVE de middernacht-poort-paal (hoogste paal):
    // die hoort niet in de groene lichtshow. Zo doen ook palen 21/22/23 mee en blijft 24 erbuiten.
    const gatePaal = palenRing.length ? Math.max.apply(null, palenRing) : null;
    for (const u of palenRing) if (u !== gatePaal) gewenst[u] = 8;
} else {
    for (const u in bord) {
        let actie = 0;
        for (const e of (bord[u].effecten || [])) { if (ACTIE[e.effect] !== undefined) { actie = ACTIE[e.effect]; break; } }
        if (actie) gewenst[u] = actie;
    }
    // Middernacht-poort op de middernacht-paal: wit (open) / rood (dicht), tenzij daar al een effect ligt.
    if (global.get("middernachtActief") === true && mnPaal != null && gewenst[mnPaal] === undefined) {
        gewenst[mnPaal] = (global.get("midnightOpen") === false) ? 10 : 9;
    }
}
// Tornado overschrijft tijdelijk de LED van het center (donkergrijs, actie 14) en de twee buururen
// (trage grijze pulse, actie 15) — wint van een eventueel onderliggend effect. Bij de controle wordt
// tornadoActief geleegd + paalLedForceRebuild gezet, zodat de oorspronkelijke LED's terugkeren.
for (const t of (global.get("tornadoActief") || [])) { if (t.center != null) gewenst[t.center] = 14; for (const r of (t.randen || [])) gewenst[r] = 15; }
// Bomaanslag-ontploffing: witte flikker (OOGST 11) op de doel-uren tot 'tot'; daarna automatisch wissen.
const _bom = global.get("bomOntploffing");
if (_bom && _bom.uren && Date.now() < _bom.tot) { for (const u of _bom.uren) gewenst[u] = 11; }
else if (_bom) { global.set("bomOntploffing", null); global.set("paalLedForceRebuild", true); }
// Volledige re-send forceren (na nuke/oogst-overgang) zodat geen paal op een oude kleur blijft hangen.
// We vullen 'vorige' met een sentinel (-1) voor ELKE ring-paal i.p.v. te legen: anders zou de uitzet-lus
// over een lege map lopen en bleef de nuke-/oogst-animatie (actie 8/11) hangen omdat er nooit actie 0 ging.
let vorige = global.get("paalLedActie") || {};
if (global.get("paalLedForceRebuild") === true) {
    vorige = {}; for (const u of palenRing) vorige[u] = -1;
    global.set("paalLedForceRebuild", false);
}
const cmds = [];
for (const u in gewenst) { if (vorige[u] !== gewenst[u]) cmds.push({ payload: { paal: parseInt(u, 10), actie: gewenst[u] } }); }
for (const u in vorige) { if (gewenst[u] === undefined) cmds.push({ payload: { paal: parseInt(u, 10), actie: 0 } }); }
global.set("paalLedActie", gewenst);

// Dramatische animatie als ÉÉN retained bericht (robuust voor de simulator: per-paal commando's
// kunnen in de burst verloren gaan over WebSocket; de firmware blijft op de per-paal acties via de FIFO).
let animType = null, animCenters = [];
if (oogstMoment) animType = "oogst";
else if (nukeActief) animType = "nuke";
else if ((global.get("tornadoActief") || []).length) { animType = "tornado"; animCenters = global.get("tornadoActief") || []; }
const animMsg = { topic: "pof/animatie", payload: { type: animType, gate: mnPaal, centers: animCenters } };

return [
    { topic: "pof/toestanden", payload: toestanden },
    { topic: "pof/portalen", payload: paren },
    cmds.length ? cmds : null,
    animMsg
];

// Multi-ronde speler-toestanden (ziekte + tijdbom) voor het Bediening-dashboard (werkt voor sim én
// echt spel: leest dezelfde globals). Toont per speler de toestand + resterende rondes + huidige paal.
let rijen = [];
const ziek = global.get("ziekeSpelers") || {};
const bommen = global.get("tijdbomSpelers") || {};
const loc = global.get("spelerLocaties") || {};
for (const n in ziek) rijen.push({ Speler:n, Toestand:"\uD83E\uDD12 Ziek", "Rondes resterend": ziek[n], Paal: loc[n] != null ? loc[n] : "?" });
for (const n in bommen) rijen.push({ Speler:n, Toestand:"\uD83D\uDCA3 Tijdbom", "Rondes resterend": bommen[n], Paal: loc[n] != null ? loc[n] : "?" });
if (!rijen.length) rijen = [{ Speler:"-", Toestand:"geen", "Rondes resterend":"-", Paal:"-" }];
msg.payload = rijen;
return msg;

const we = global.get("wereldEffecten") || [];
let rijen = we.map(e => ({ Effect: e.naam, "Rondes resterend": e.resterendeRondes }));
if (!rijen.length) rijen = [{ Effect: "geen actieve wereld-effecten", "Rondes resterend": "-" }];
msg.payload = rijen;
return msg;

// Wis alle blijvende effecten (handig bij testen / herstart van een cyclus).
global.set("bordStaat", {});
global.set("spelerEffecten", {});
global.set("wereldEffecten", []);
msg.payload = "rebuild";
return msg;

// Controle: scoort op basis van het OPGENOMEN PAD (geordende hops), actie per actie.
// STAP = 1 levensuur (nooit achteruit); TELEPORT (tussen twee actieve portaal-palen) =
// 0 stappen, geen richtingcheck. Geen netto begin/eind-vergelijking.
const v = global.get("pofVerificatie") || {};
const loc = global.get("spelerLocaties") || {};
const se = global.get("spelerEffecten") || {};
const we = global.get("wereldEffecten") || [];
const bord = global.get("bordStaat") || {};
const ziek = global.get("ziekeSpelers") || {};
const dienaars = global.get("dienaars") || {};
const mnDicht = global.get("middernachtActief") === true && global.get("midnightOpen") === false;
const mnPaal = global.get("middernachtPaal");
const tijdreizen = global.get("tijdreizenActief") === true;
const pad = global.get("pofPad") || {};
const vrijPad = global.get("pofVrijPad") || {};   // hops buiten een event (V10: vrij wandelen is verboden)
const gepauzeerd = global.get("gespauzeerdePlayers") || {};   // pauze = volledig uit het spel (niet scoren)
let stats = global.get("spelerStats") || {};
const avond = global.get("avondModus") === true;
const palen = (global.get("palenActief") || global.get("paaltjesLijst") || []).slice().sort((a, b) => a - b);
const N = palen.length;
const idx = (p) => palen.indexOf(p);

// Na elke controle: vrij-wandel-register leegmaken + korte genade-drempel zodat een hop die pas
// na de controle settelt niet alsnog als "vrij gewandeld" wordt aangerekend.
function resetVrijLoop() {
    global.set("pofVrijPad", {});
    const _sg = global.get("pofSettleGrace");
    const _sgv = (_sg === undefined || _sg === null) ? 3 : Number(_sg);
    global.set("pofVrijVanaf", Date.now() + Math.max(0, _sgv) * 1000);
}

function portaalPartner(p) {
    const fx = ((bord[p] || {}).effecten || []).find(e => e.effect === "portaal" && e.data && e.data.partner != null);
    return fx ? fx.data.partner : null;
}

// Ontleed het pad van een speler -> voorwaartse/achterwaartse stappen, teleports, geldigheid.
function ontleed(hops) {
    let voor = 0, achter = 0, ongeldig = false, bewogen = false, kruist = false, kruistAchter = false;
    const portaalGebruik = {};
    for (const h of (hops || [])) {
        bewogen = true;
        const van = h[0], naar = h[1];
        if (portaalPartner(van) === naar) {            // TELEPORT
            const key = van < naar ? van + "-" + naar : naar + "-" + van;
            portaalGebruik[key] = (portaalGebruik[key] || 0) + 1;
            if (portaalGebruik[key] > 1) ongeldig = true;   // max 1x per portaal per zet
            continue;
        }
        const iv = idx(van), inr = idx(naar);
        if (N < 2 || iv < 0 || inr < 0) continue;
        const fd = (((inr - iv) % N) + N) % N;
        const bd = N - fd;
        if (fd <= bd) { voor += fd; if (inr < iv) kruist = true; } else { achter += bd; if (inr > iv) kruistAchter = true; }   // forward-wrap = midnight-oversteek; backward-wrap = achterwaartse oversteek
    }
    return { voor, achter, ongeldig, bewogen, kruist, kruistAchter };
}

const doelwitSet = new Set(v.doelwit || []);
const start = v.startPosities || {};
const voorwaarde = v.voorwaarde || "geen";
const x = v.getal;
const y = v.getal2;
const bewegingEvent = (voorwaarde === "min" || voorwaarde === "max" || voorwaarde === "of");

// NUKE (wereld-event): geen bewegings-straffen — iedereen mocht vluchten. Wie bij de controle nog
// gedetecteerd is (in spelerLocaties) zat binnen het bereik en ONTPLOFT (uren 0 + sterfte); wie
// ontkomen is (onder de RSSI-vloer / buiten het veld, dus weg uit spelerLocaties) is VEILIG.
const _huidig = global.get("pofHuidigEvent") || {};
if ((_huidig.gevolgen || []).some(g => g.type === "nuke")) {
    let nrijen = [];
    for (const naam in start) {
        let s = stats[naam] || {}; if (s.totaalUren === undefined) s.totaalUren = 0; if (s.sterftes === undefined) s.sterftes = 0;
        const gedetecteerd = loc[naam] != null;
        let st;
        if (gedetecteerd) { s.totaalUren = 0; s.sterftes += 1; st = "ONTPLOFT"; }
        else st = "VEILIG (ontkomen)";
        stats[naam] = s;
        nrijen.push({ Speler: naam, Tag: "-", Verplaatst: gedetecteerd ? "in zone" : "uit zone", Status: st, _status: st, _delta: gedetecteerd ? "-alles" : 0 });
    }
    global.set("spelerStats", stats);
    global.set("pofPad", {}); resetVrijLoop();
    // TW5: een nuke breekt GEEN tweelingbanden en propageert geen mee-sterven -- global.tweelingen
    // blijft hier bewust onaangeroerd (iedereen ontplofte tegelijk, niemand "trok" de ander mee).
    // Een nuke wist de wereld: ruim ook de ziekte-episode (zieken + medicijnen) en dienaars op.
    // 'Ziekte-beheer' (via output 1) herpubliceert daarna lege pof/ziekte + pof/dienaars en herstelt de LEDs.
    global.set("ziekeSpelers", {});
    global.set("dienaars", {}); global.set("luisterNaam", {});
    global.set("tijdbomSpelers", {});
    global.set("tijdbomOntmantelPalen", []);
    for (const _u in bord) { const _fx = ((bord[_u].effecten) || []).filter(e => e.effect !== "medicijn" && e.effect !== "tijdbom"); if (_fx.length) bord[_u].effecten = _fx; else delete bord[_u]; }
    global.set("bordStaat", bord);
    global.set("nukeActief", false); global.set("paalLedForceRebuild", true);   // ring weg, LEDs herstellen
    // Regroup-fase i.p.v. de normale aanloop.
    global.set("pofFase", "regroup");
    global.set("pofTeller", _huidig.regroup_s || 45);
    const nctrl = { topic: "pof/controle", payload: { event: "Nuke", resultaten: nrijen.map(r => ({ speler: r.Speler, status: r._status, verplaatst: r.Verplaatst, delta: r._delta, tag: "-" })) } };
    const ntabel = nrijen.map(r => ({ Speler: r.Speler, Tag: r.Tag, Verplaatst: r.Verplaatst, Status: r.Status }));
    global.set("pofLaatsteControle", ntabel);
    msg.payload = ntabel.length ? ntabel : [{ Speler:"-", Tag:"-", Verplaatst:"-", Status:"geen spelers" }];
    return [msg, nctrl];
}

// TORNADO (toestand-event): spelers op een aanliggend uur worden naar het center gezogen. Wie niet
// volgt, verliest AL zijn levensuren (GEEN sterfte). Andere spelers blijven ongemoeid. Eén-shot: hierna
// wordt tornadoActief geleegd en keren de LED's terug naar hun oorspronkelijke staat.
if ((_huidig.gevolgen || []).some(g => g.type === "tornado")) {
    const torns = global.get("tornadoActief") || [];
    const randNaarCenter = {};
    for (const t of torns) for (const r of (t.randen || [])) randNaarCenter[r] = t.center;
    let trijen = [];
    for (const naam in start) {
        let s = stats[naam] || {}; if (s.totaalUren === undefined) s.totaalUren = 0; if (s.sterftes === undefined) s.sterftes = 0;
        const vanaf = start[naam];
        let st, delta = 0;
        if (randNaarCenter[vanaf] != null) {
            const moet = randNaarCenter[vanaf];
            if (loc[naam] === moet) { st = "GEVOLGD"; delta = 0; }
            else { delta = -s.totaalUren; s.totaalUren = 0; st = "WEGGEZOGEN"; }
        } else { st = "OK"; delta = 0; }
        stats[naam] = s;
        const dStr = (delta >= 0 ? "+" : "") + delta;
        trijen.push({ Speler: naam, Tag: "tornado", Verplaatst: "-", Status: st + " (" + dStr + " uur)", _status: st, _delta: delta });
    }
    global.set("spelerStats", stats);
    global.set("pofPad", {}); resetVrijLoop();
    global.set("tornadoActief", []);
    global.set("paalLedForceRebuild", true);
    const manueelT = global.get("pofManueel") === true;
    global.set("pofFase", manueelT ? "wacht" : "aanloop");
    global.set("pofTeller", manueelT ? 0 : 5);
    const tctrl = { topic: "pof/controle", payload: { event: "Tornado", resultaten: trijen.map(r => ({ speler: r.Speler, status: r._status === "WEGGEZOGEN" ? "WEGGEZOGEN" : "OK", verplaatst: r.Verplaatst, delta: r._delta, tag: "tornado" })) } };
    const ttabel = trijen.map(r => ({ Speler: r.Speler, Tag: r.Tag, Verplaatst: r.Verplaatst, Status: r.Status }));
    global.set("pofLaatsteControle", ttabel);
    msg.payload = ttabel.length ? ttabel : [{ Speler:"-", Tag:"-", Verplaatst:"-", Status:"geen spelers" }];
    return [msg, tctrl];
}

// BOMAANSLAG: na de 3s-waarschuwing ontploft de bom. Wie DAN op een doel-uur staat verliest 'uur'
// levensuren (vluchten in de 3s mag, geen bewegingsstraf - net als bij NUKE). Witte flikker via Sync.
if ((_huidig.gevolgen || []).some(g => g.type === "bom")) {
    const bomUren = v.doelwit || [9, 11];
    let brijen = [];
    for (const naam in start) {
        let s = stats[naam] || {}; if (s.totaalUren === undefined) s.totaalUren = 0; if (s.sterftes === undefined) s.sterftes = 0;
        const u = loc[naam];
        if (bomUren.indexOf(u) >= 0) {
            const verloren = Math.min(s.totaalUren, u);
            s.totaalUren = Math.max(0, s.totaalUren - u); stats[naam] = s;
            brijen.push({ Speler: naam, Tag: "bom", Verplaatst: "uur " + u, Status: "GERAAKT (-" + verloren + " uur)", _status: "GERAAKT", _delta: -verloren });
        } else {
            brijen.push({ Speler: naam, Tag: "-", Verplaatst: "-", Status: "VEILIG", _status: "VEILIG", _delta: 0 });
        }
    }
    global.set("spelerStats", stats);
    global.set("pofPad", {}); resetVrijLoop();
    global.set("bomOntploffing", { uren: bomUren, tot: Date.now() + 3000 });
    global.set("paalLedForceRebuild", true);
    const manueelB = global.get("pofManueel") === true;
    global.set("pofFase", manueelB ? "wacht" : "aanloop");
    global.set("pofTeller", manueelB ? 0 : 5);
    const bctrl = { topic: "pof/controle", payload: { event: "Bomaanslag", resultaten: brijen.map(r => ({ speler: r.Speler, status: r._status, verplaatst: r.Verplaatst, delta: r._delta, tag: r.Tag })) } };
    const btabel = brijen.map(r => ({ Speler: r.Speler, Tag: r.Tag, Verplaatst: r.Verplaatst, Status: r.Status }));
    global.set("pofLaatsteControle", btabel);
    msg.payload = btabel.length ? btabel : [{ Speler: "-", Tag: "-", Verplaatst: "-", Status: "geen spelers" }];
    return [msg, bctrl];
}

let rijen = [];
let genezen = [];
const _bewogen = {};           // tweeling: wie bewoog deze ronde (samen-bewegen-regel)
const _basis = {};             // basis-status per speler (voor wolf-legaliteit + tweeling-winst)
const _vrijGelopen = {};       // wie deze ronde vrij wandelde (V10)
const _winst = {};             // positieve delta die deze ronde daadwerkelijk toegekend werd
const _winstNaar = {};         // aan wie die winst geboekt is (speler zelf, of zijn meester)
const _sterfteSnap = {}; for (const _n in start) _sterfteSnap[_n] = (stats[_n] || {}).sterftes || 0;  // tweeling: dood-detectie
// Valsspeel: deze (basis)statussen = een foute verplaatsing -> +1 valsspeelpunt + slechtere aura.
const _VALS_FOUT = new Set(["TERUG IN TIJD", "PENDELEN", "TE VEEL", "TE WEINIG", "ONGELDIGE KEUZE", "BEWOOG (mocht niet)", "ONGELDIGE TELEPORT", "MIDDERNACHT DICHT", "NIET GEWISSELD", "TE WEINIG SAMEN"]);
// --- Item 1 (body-swap) / 5 (max per uur) / 6 (polonaise) voorbereiding ---
const _isWissel = (voorwaarde === "wissel");
const _wisselPartner = {};
if (_isWissel) { const _dw = Array.from(doelwitSet); if (_dw.length === 2) { _wisselPartner[_dw[0]] = _dw[1]; _wisselPartner[_dw[1]] = _dw[0]; } }
const _maxPerUur = Number(global.get("maxPerUur"));
const _geenWinst = global.get("geenWinstVolgende") || {};
const _polon = global.get("polonaiseActief") === true && _huidig.categorie === "verplaatsing";
const _vertrekPerUur = {};
if (_polon) { for (const _nm in start) { if (gepauzeerd[_nm] === true) continue; if (start[_nm] != null && loc[_nm] != null && loc[_nm] !== start[_nm]) _vertrekPerUur[start[_nm]] = (_vertrekPerUur[start[_nm]] || 0) + 1; } }
for (const naam in start) {
    let s = stats[naam] || {};
    if (s.totaalUren === undefined) s.totaalUren = 0;
    if (s.sterftes === undefined) s.sterftes = 0;
    if (s.tijdTerug === undefined) s.tijdTerug = false;
    if (s.startUur == null && start[naam] != null) s.startUur = start[naam];   // thuisbank: startuur van deze partij

    if (gepauzeerd[naam] === true) { stats[naam] = s; _bewogen[naam] = false; rijen.push({ Speler: naam, Tag: "pauze", Verplaatst: 0, Status: "GEPAUZEERD (0 uur)", _status: "GEPAUZEERD", _delta: 0 }); continue; }
    const heeftBlok = (se[naam] || []).some(e => e.effect === "mag_niet_bewegen");
    const r = ontleed(pad[naam]);
    _bewogen[naam] = r.bewogen;
    _vrijGelopen[naam] = (vrijPad[naam] || []).length > 0;
    const isDoel = bewegingEvent && doelwitSet.has(naam);
    const _wisselVrij = (_isWissel && doelwitSet.has(naam));   // body-swap: elke route is legaal, veld-conflicten tellen niet
    let status, delta = 0;

    if (heeftBlok) { status = "GEBLOKKEERD"; delta = 0; }
    else if (_isWissel && doelwitSet.has(naam)) {
        // Body-swap (item 1): geen beloning; correct = eindig op de STARTpaal van je partner. Anders = foute zet.
        const _p = _wisselPartner[naam];
        if (_p != null && loc[naam] === start[_p]) { status = "OK (gewisseld)"; delta = 0; }
        else { status = "NIET GEWISSELD"; delta = 0; }
    }
    else if (isDoel) {
        // Tijdreizen (wereld): achteruit in de tijd telt mee als geldige beweging (niet bestraft) -> stapp = voor+achter.
        // Je moet wel EEN richting kiezen: heen-en-weer pendelen (voor > 0 en achter > 0) = PENDELEN, delta 0.
        // Enkel een ACHTERWAARTSE middernacht-oversteek (kruistAchter) blijft verboden. Zonder tijdreizen = klassiek.
        const stapp = r.voor + (tijdreizen ? r.achter : 0);
        if (r.ongeldig) { status = "ONGELDIGE TELEPORT"; delta = 0; }   // valsspel: nooit negatief, enkel geen winst
        else if (tijdreizen && r.kruistAchter) { status = "TERUG IN TIJD"; delta = Math.max(0, r.voor - r.achter); }
        else if (!tijdreizen && r.achter > 0) { status = "TERUG IN TIJD"; delta = Math.max(0, r.voor - r.achter); }
        else if (tijdreizen && r.voor > 0 && r.achter > 0) { status = "PENDELEN"; delta = 0; }   // tijdreizen: kies 1 richting, niet heen-en-weer
        else if (voorwaarde === "max" && stapp > x) { status = "TE VEEL"; delta = Math.max(0, x - (stapp - x)); }   // proportioneel minder: overschot eet de winst, vloer 0
        else if (voorwaarde === "min" && stapp < x) { status = "TE WEINIG"; delta = Math.max(0, stapp - (x - stapp)); }
        else if (voorwaarde === "of" && stapp !== x && stapp !== y) { status = "ONGELDIGE KEUZE"; delta = Math.max(0, stapp - Math.min(Math.abs(stapp - x), Math.abs(stapp - y))); }
        else { status = "OK"; delta = stapp; }
    } else {
        // Niet-(bewegings)doelwit: moet stil blijven staan.
        if (!r.bewogen && !r.ongeldig) { status = "OK (stil)"; delta = 0; }
        else { status = "BEWOOG (mocht niet)"; delta = 0; }
    }

    // Middernacht GATE-BLOCK: een doelwit dat tegen de DICHTE poort wordt tegengehouden (eindigt op de
    // poort-paal zonder over te steken) mag NIET bestraft worden voor te weinig/ongeldige keuze — de poort
    // verhinderde de rest. Bv. op uur 22 met max 5 mag je 2 (tot 24); een of-event 3/6 dat maar 2 toelaat = OK.
    const _gateGeblokkeerd = (mnDicht && mnPaal != null && isDoel && !r.kruist && loc[naam] === mnPaal);
    if (_gateGeblokkeerd) {
        const gateDist = ((idx(mnPaal) - idx(start[naam])) % N + N) % N;
        if (r.voor > 0 && r.voor === gateDist && (status === "TE WEINIG" || status === "ONGELDIGE KEUZE")) { status = "OK"; delta = r.voor; }
        // M10: hij stond al OP de poort. Het event beveelt hem te bewegen, de dichte poort verbiedt het.
        // Dat mag hem geen levensuren of valsspeelpunt kosten -- het spel spreekt zichzelf tegen.
        else if (gateDist === 0 && r.voor === 0) { status = "OK (poort blokkeert)"; delta = 0; }
    }
    // Middernacht-poort dicht: OVERSTEKEN (voorwaartse wrap over de poort, r.kruist) mag niet.
    // Straf = alle levensuren kwijt + 1 sterfte (toegepast in het apply-blok hieronder). Wie naar de
    // poort-paal loopt zonder over te steken (kruist=false) blijft ongestraft staan tot de poort opent.
    let mnKruisDood = false;
    if (mnDicht && r.kruist && !_wisselVrij) { status = "MIDDERNACHT DICHT"; mnKruisDood = true; delta = 0; }
    // Middernacht-stilstand (item 3): stil blijven op de dichte (rode) poort kost 1 levensuur/ronde (positioneel, geen valsspeel).
    // M9: enkel voor wie NIET door een verplaatsingsevent tot bewegen gedwongen wordt (M10).
    if (mnDicht && mnPaal != null && loc[naam] === mnPaal && !r.bewogen && !mnKruisDood && !_wisselVrij && !isDoel) { delta -= 1; status += " | MIDDERNACHT STIL (-1)"; }
    // Polonaise (item 6): vertrek met >=4 van hetzelfde uur; <4 = foute zet, boven 4 = +1 levensuur per extra medevertrekker.
    let _polonBonus = 0;
    if (_polon && isDoel && r.bewogen && loc[naam] !== start[naam]) {
        const _M = _vertrekPerUur[start[naam]] || 0;
        if (_M < 4) { status = "TE WEINIG SAMEN"; delta = 0; }
        else if (status === "OK") { _polonBonus = _M - 4; }
    }
    let _teltMee = (status === "OK");   // S7: alleen een LEGALE zet (basis-status OK, dus geen straf/dichte-poort-oversteek) telt voor doel verplaats X uur
    if (_polonBonus > 0) { delta += _polonBonus; status = "OK (polonaise +" + _polonBonus + ")"; }
    const _basisStatus = status;   // het kale oordeel, vóór god-punt-/vrij-wandel-suffixen (ziekte-genezing leest dit)
    _basis[naam] = _basisStatus;

    // Valsspeel / GOD-PUNT. Een foute verplaatsing wordt normaal bestraft (apply-blok) + telt als valsspelen.
    // Maar met een god-punt (saldo > 0) speelt de speler ONGESTRAFT vals: 1 god-punt op, geen levensuren/
    // sterfte, geen valsspeelpunt. (verplaatsingen gelden altijd; midnight-oversteek in gesloten toestand mag;
    // een ziek persoon mag zo naar een medicijn-paal lopen en genezen.) Zonder god-punt: +1 valsspeelpunt +3% aura.
    let godVrij = false;
    if (_VALS_FOUT.has(status)) {
        if ((s.godPunten || 0) > 0) { s.godPunten -= 1; godVrij = true; delta = 0; mnKruisDood = false; status += " [GOD-PUNT]"; }
        else { s.valsspeelpunten = (s.valsspeelpunten || 0) + 1; s.auraValsspeel = (s.auraValsspeel || 0) + 3; }
    }

    // Vrij wandelen (V10): verplaatsen buiten een event blokkeert de eerstvolgende winst en kost
    // 1 valsspeelpunt (+3% aura). GEEN levensuren-verlies, dus geen sterfte (V11) - een RSSI-flapper
    // kan je niet doden. Een god-punt vergeeft het volledig; datzelfde punt dekt ook een foute zet
    // in dezelfde ronde. Body-swap-doelwitten zijn vrijgesteld; gepauzeerden zijn er al uit.
    if ((vrijPad[naam] || []).length > 0 && !_wisselVrij) {
        if (godVrij) { status += " | VRIJ GEWANDELD [GOD-PUNT]"; }
        else if ((s.godPunten || 0) > 0) { s.godPunten -= 1; godVrij = true; status += " | VRIJ GEWANDELD [GOD-PUNT]"; }
        else {
            if (delta > 0) delta = 0;
            s.valsspeelpunten = (s.valsspeelpunten || 0) + 1;
            s.auraValsspeel = (s.auraValsspeel || 0) + 3;
            status += " | VRIJ GEWANDELD (0 uur)";
            _teltMee = false;   // S7: vals gelopen uren tellen niet voor het doel
        }
    }

    // Ziekte-modifier: zieke speler loopt door de NORMALE controle (geen vrijstelling). Hij verdient
    // geen levensuren (winst -> 0), maar verliest wel bij onwettige zetten. Genezen kan ENKEL als de zet
    // legaal was (OK / OK (stil)) en hij op een medicijn-uur eindigt.
    if (!mnKruisDood && ziek[naam] != null) {
        if (delta > 0) delta = 0;
        const legaal = (_basisStatus === "OK" || _basisStatus === "OK (stil)");
        const opMed = ((bord[loc[naam]] || {}).effecten || []).some(e => e.effect === "medicijn");
        // God-punt laat een ziek persoon ook na een (ongestrafte) foute zet genezen op een medicijn-paal.
        if ((legaal || godVrij) && opMed) { status = (godVrij ? status + " -> GENEZEN" : "GENEZEN"); genezen.push({ naam: naam, uur: loc[naam] }); }
        else if (legaal) { status = "ZIEK"; }
    }

    // Max/uur (item 5): wie vorige ronde op/naast een overvol uur zat, verdient deze zet niets.
    if (_geenWinst[naam] === true && delta > 0 && !_wisselVrij) { delta = 0; status += " | MAX/UUR (geen winst)"; }
    // Avond: verplaatsing KOST levensuren i.p.v. verdient (positieve winst wordt een kost).
    if (avond && delta > 0) delta = -delta;

    // Happy hour x2 op een LEGAAL verdiende beloning (eindpaal heeft happy_hour).
    if (delta > 0) {
        const happy = ((bord[loc[naam]] || {}).effecten || []).some(e => e.effect === "happy_hour");
        if (happy) { delta *= 2; status += " (happy hour x2)"; }
    }
    // Toepassen + sterfte. Een DIENAAR verdient niets voor zichzelf: positieve winst gaat naar de meester
    // (die kan ze niet meer verliezen); verlies + sterfte blijven wel bij de dienaar.
    if (mnKruisDood) {
        // Oversteek bij dichte poort: autoritair bij de controle (alle levensuren weg + 1 sterfte).
        // Dedup (M3a): als de live poort-bewaker deze speler deze ronde al strafte, niet nog eens.
        const _mng = global.get("mnGestraft") || {};
        if (_mng[naam]) { delta = 0; status += " (al bestraft deze ronde)"; }
        else { delta = -(s.totaalUren); s.totaalUren = 0; s.sterftes += 1; status += " -> STERFTE"; _mng[naam] = true; global.set("mnGestraft", _mng); }
