global.set("pofDoelwitReveal", "");

const spelersLijst = global.get("spelersLijst") || {};
const loc = global.get("spelerLocaties") || {};
const se = global.get("spelerEffecten") || {};
const we = global.get("wereldEffecten") || [];
const bord = global.get("bordStaat") || {};
const doelSet = new Set(doelwit);
let beginRijen = [];
for (const mac in spelersLijst) {
    const naam = spelersLijst[mac];
    const paalFX = ((bord[loc[naam]] || {}).effecten || []).map(e => e.naam);
    const allFX = [...(se[naam] || []).map(e => e.naam), ...we.map(e => e.naam), ...paalFX];
    beginRijen.push({ Speler: naam, Tag: allFX.length ? allFX.join(", ") : "-", Verplaatst: 0, Status: doelSet.has(naam) ? "afwachten..." : "-" });
}
if (!beginRijen.length) beginRijen = [{ Speler:"-", Tag:"-", Verplaatst:"-", Status:"afwachten..." }];

// R4: generation-token -- na een Stop/reset (resetPartij verhoogt pofGeneration) mogen deze
// geplande sends niet meer vuren (geen gevolgen/LED/buzzer op een gestopt spel).
const _gen = global.get("pofGeneration") || 0;
namen.forEach((naam, i) => {
    setTimeout(() => {
        if ((global.get("pofGeneration") || 0) !== _gen) return;
        lijnen.push("- " + naam);
        const tekst = lijnen.join("\n");
        global.set("pofDoelwitReveal", tekst);
        const buzz = uurType ? { payload: { paal: naam, actie: 3 } } : null;
        node.send([{ payload: tekst }, null, null, buzz]);
    }, i * STAP);
});
setTimeout(() => { if ((global.get("pofGeneration") || 0) !== _gen) return; node.send([null, msg, null, null]); }, namen.length * STAP + 600);
return [null, null, { payload: beginRijen }, null];

let P = global.get("locParams");
if (!P) { P = { vensterMs:6000, hystereseDbm:6, rssiVloer:-92, graceMs:4000, switchSamples:2, minSamples:2 }; global.set("locParams", P); }
let PR = global.get("locPresets");
if (!PR) { PR = { dag: Object.assign({}, P), avond: Object.assign({}, P) }; global.set("locPresets", PR); }
return [ {payload:P.vensterMs}, {payload:P.hystereseDbm}, {payload:P.rssiVloer}, {payload:P.graceMs}, {payload:P.switchSamples}, {payload:P.minSamples} ];

let P = global.get("locParams") || {};
const map = { venster:"vensterMs", hysterese:"hystereseDbm", vloer:"rssiVloer", grace:"graceMs", switch:"switchSamples", minsamp:"minSamples" };
const k = map[msg.topic];
if (k) { P[k] = Number(msg.payload); global.set("locParams", P); }
msg.payload = "Actief: " + JSON.stringify(global.get("locParams"));
return msg;

// Scan-duur controller. Bouwt {paal, actie:20, scan_ms} -> Route commando (out1),
// feedback -> ui-text (out2), retained config-object -> mqtt-out config/scan-duur (out3).
const ACTIE = 20;
const clamp = (v) => Math.min(1000, Math.max(400, Math.round(Number(v) || 0)));
let st = flow.get("scanDuurUi") || { paal: 1, paalMs: 700 };
const palen = global.get("paaltjesLijst") || Array.from({ length: 24 }, (_, i) => i + 1);
const t = msg.topic;
function stuur(paal, ms) { node.send([{ payload: { paal: Number(paal), actie: ACTIE, scan_ms: ms } }, null, null]); }
if (t === "paal")   { st.paal = Number(msg.payload); flow.set("scanDuurUi", st); return null; }
if (t === "paalMs") { st.paalMs = clamp(msg.payload); flow.set("scanDuurUi", st); return null; }
if (t === "alle") {
    const ms = clamp(msg.payload);
    let perPaal = global.get("scanDuurPerPaal") || {};
    let laatst  = global.get("scanDuurLaatst")  || {};
    palen.forEach((p) => { perPaal[p] = ms; laatst[p] = ms; stuur(p, ms); });
    global.set("scanDuurPerPaal", perPaal); global.set("scanDuurLaatst", laatst);
    return [null, { payload: "Alle slaves -> " + ms + " ms" }, { payload: perPaal }];
}
if (t === "zetPaal") {
    const paal = Number(st.paal), ms = clamp(st.paalMs);
    let perPaal = global.get("scanDuurPerPaal") || {};
    let laatst  = global.get("scanDuurLaatst")  || {};
    perPaal[paal] = ms; laatst[paal] = ms;
    global.set("scanDuurPerPaal", perPaal); global.set("scanDuurLaatst", laatst);
    stuur(paal, ms);
    return [null, { payload: "Paal " + paal + " -> " + ms + " ms" }, { payload: perPaal }];
}
return null;

// Auto-herstel scan-duur na slave-reboot. Op elke heartbeat ({hb:1,uptime}): als voor die paal
// een scan-duur ingesteld is en (a) ze nog niet gestuurd is of (b) de slave rebootte (uptime daalde),
// (her)stuur {paal,actie:20,scan_ms} naar Route commando. Detecties/andere berichten worden genegeerd.
const p = msg.payload;
if (!p || p.hb !== 1 || !p.paal) return null;
const perPaal = global.get("scanDuurPerPaal") || {};
const ms = perPaal[p.paal];
if (ms === undefined) return null;
const upt = global.get("scanDuurUptime") || {};
const laatst = global.get("scanDuurLaatst") || {};
const prevUp = upt[p.paal];
const rebooted = (typeof p.uptime === "number") && (prevUp !== undefined) && (p.uptime < prevUp);
upt[p.paal] = p.uptime; global.set("scanDuurUptime", upt);
if (!rebooted && laatst[p.paal] === ms) return null;
laatst[p.paal] = ms; global.set("scanDuurLaatst", laatst);
return { payload: { paal: Number(p.paal), actie: 20, scan_ms: ms } };

// Herstel de scan-duur-config in global bij (her)start van Node-RED uit het retained topic.
if (msg.payload && typeof msg.payload === "object") global.set("scanDuurPerPaal", msg.payload);
return null;

// LED-helderheid controller. Slider (topic led) + presets (topic ledPreset) zetten EEN globale
// helderheid (10..255) en sturen {paal, actie:21, helderheid} naar ALLE palen.
// out1 -> Route commando | out2 -> ui-text | out3 -> retained config/led-helderheid.
const ACTIE = 21;
const clamp = (v) => Math.min(255, Math.max(10, Math.round(Number(v) || 0)));
const t = msg.topic;
if (t !== "led" && t !== "ledPreset") return null;
const h = clamp(msg.payload);
global.set("ledHelderheid", h);
const palen = global.get("paaltjesLijst") || Array.from({ length: 24 }, (_, i) => i + 1);
palen.forEach((p) => node.send([{ payload: { paal: Number(p), actie: ACTIE, helderheid: h } }, null, null]));
return [null, { payload: "LED-helderheid -> " + h + " (alle palen)" }, { payload: h }];

// Auto-herstel LED-helderheid na slave-reboot. Op elke heartbeat ({hb:1,uptime}): (her)stuur de
// ingestelde helderheid als de slave rebootte (uptime daalde) of ze nog niet gestuurd is.
const p = msg.payload;
if (!p || p.hb !== 1 || !p.paal) return null;
const h = global.get("ledHelderheid");
if (h === undefined) return null;
const upt = global.get("ledHelderheidUptime") || {};
const laatst = global.get("ledHelderheidLaatst") || {};
const prevUp = upt[p.paal];
const rebooted = (typeof p.uptime === "number") && (prevUp !== undefined) && (p.uptime < prevUp);
upt[p.paal] = p.uptime; global.set("ledHelderheidUptime", upt);
if (!rebooted && laatst[p.paal] === h) return null;
laatst[p.paal] = h; global.set("ledHelderheidLaatst", laatst);
return { payload: { paal: Number(p.paal), actie: 21, helderheid: h } };

// Herstel de LED-helderheid in global bij (her)start van Node-RED uit het retained topic.
if (typeof msg.payload === "number") global.set("ledHelderheid", msg.payload);
return null;

// Verzamel per beacon-MAC ruwe RSSI-samples voor stabiliteitsanalyse.
const d = msg.payload;
if (!d || d.mac === undefined || d.rssi === undefined) return null; // batterij-regels overslaan
const nu = Date.now();
let buf = global.get("beaconBuf") || {};
(buf[d.mac] = buf[d.mac] || []).push({ rssi: d.rssi, ts: nu, paal: d.paal });
if (buf[d.mac].length > 400) buf[d.mac] = buf[d.mac].slice(-400);
// N2-prune (1x/30s): MACs die >60 s stil zijn wissen, zodat de begrenzing niet afhangt van de
// 2s-inject van de Beacon-tabel (die pruned ook, maar enkel zolang die UI-tick draait).
const _vorige = context.get("bufPruneTs") || 0;
if (nu - _vorige > 30000) {
    context.set("bufPruneTs", nu);
    for (const _m of Object.keys(buf)) {
        const _l = buf[_m];
        if (!_l.length || (nu - _l[_l.length - 1].ts) > 60000) delete buf[_m];
    }
}
global.set("beaconBuf", buf);
return null;

const nu = Date.now();
const VENSTER = 15000;
let buf = global.get("beaconBuf") || {};
const spelers = global.get("spelersLijst") || {};
const kal = global.get("beaconKalibratie") || {};
let rows = [], lijst = [];
for (const mac in buf) {
    let arr = buf[mac].filter(x => nu - x.ts <= VENSTER);
    buf[mac] = arr;
    if (!arr.length) { delete buf[mac]; continue; }
    const n = arr.length;
    const dur = Math.max(1, (nu - arr[0].ts) / 1000);
    const rate = n / dur;
    const mean = arr.reduce((a,b)=>a+b.rssi,0)/n;
    const sd = Math.sqrt(arr.reduce((a,b)=>a+Math.pow(b.rssi-mean,2),0)/n);
    let maxGap = 0;
    for (let i=1;i<arr.length;i++) maxGap = Math.max(maxGap, arr[i].ts-arr[i-1].ts);
    const palen = new Set(arr.map(x=>x.paal)).size;
    let score = 100 - sd*4 - Math.max(0,maxGap-1500)/40 - Math.max(0,3-rate)*15;
    score = Math.max(0, Math.min(100, Math.round(score)));
    let advies = "OK";
    if (rate < 1.2) advies = "adv-interval verlagen (300 ms)";
    else if (maxGap > 4000) advies = "mist advertenties - batterij/positie";
    else if (sd > 8) advies = "plaatsing/antenne/tx-power";
    const naam = spelers[mac] || "(onbekend)";
    rows.push({ Beacon: naam, MAC: mac, Rate: rate.toFixed(1), "RSSI sigma": sd.toFixed(1), MaxGap: Math.round(maxGap)+"ms", Palen: palen, Score: score, Offset: (kal[mac]||0)+" dB", Advies: advies });
    lijst.push({ mac, naam, offset: kal[mac]||0, score });
}
global.set("beaconBuf", buf);
rows.sort((a,b)=>a.Score-b.Score);
lijst.sort((a,b)=>a.score-b.score);
return [{ payload: rows }, { payload: lijst }];

// Spelers/bakens-beheer. Koppel het laatst-geziene NIEUWE baken aan een gekozen speler, of ontkoppel.
// Schrijft global.spelersLijst + publiceert retained config/spelers. Consumenten lezen per bericht.
// in: dropdown (naam, geen topic) | knop koppel/ontkoppel | inject tick
// out1 config/spelers | out2 ui-text baken | out3 ui-text feedback | out4 ui-table | out5 dropdown-opties
const spelers = global.get("spelersLijst") || {};
const eig = global.get("spelerEigenschappen") || {};
const macSeen = global.get("status_lastSeenMac") || {};
let st = flow.get("spelerBeheer") || { naam: null, optSig: "" };
const t = msg.topic;
function laatstNieuwBaken() {
    let best = null, bestTs = -1;
    for (const mac in macSeen) {
        if (spelers[mac]) continue;
        if (macSeen[mac] > bestTs) { bestTs = macSeen[mac]; best = mac; }
    }
    return best;
}
function tabelRijen() {
    return Object.keys(spelers)
        .sort((a, b) => (spelers[a] || "").localeCompare(spelers[b] || "", "nl-BE"))
        .map(mac => ({ Speler: spelers[mac], MAC: mac }));
}
function optiesMsg() {
    const namen = Object.keys(eig).length ? Object.keys(eig) : Object.values(spelers);
    const o = namen.sort((a, b) => a.localeCompare(b, "nl-BE")).map(n => ({ label: n, value: n }));
    const sig = JSON.stringify(o);
    if (sig === st.optSig) return null;
    st.optSig = sig; flow.set("spelerBeheer", st);
    return { options: o };
}
function bakenTekst() {
    const m = laatstNieuwBaken();
    return { payload: m ? ("baken " + m) : "(geen nieuw baken gezien - wapper het bij een paal)" };
}
function publiceer(fb) {
    global.set("spelersLijst", spelers);
    return [ { payload: spelers }, bakenTekst(), { payload: fb }, { payload: tabelRijen() }, optiesMsg() ];
}
if (!t && typeof msg.payload === "string") { st.naam = msg.payload; flow.set("spelerBeheer", st); return null; }
if (t === "tick") { return [ null, bakenTekst(), null, { payload: tabelRijen() }, optiesMsg() ]; }
if (t === "koppel") {
    if (!st.naam) return [null, null, { payload: "Kies eerst een speler." }, null, null];
    const mac = laatstNieuwBaken();
    if (!mac) return [null, null, { payload: "Geen nieuw baken gezien - wapper het baken bij een paal." }, null, null];
    for (const m in spelers) if (spelers[m] === st.naam) delete spelers[m];
    spelers[mac] = st.naam;
    return publiceer("Gekoppeld: " + mac + " -> " + st.naam);
}
if (t === "ontkoppel") {
    if (!st.naam) return [null, null, { payload: "Kies eerst een speler." }, null, null];
    let weg = null;
    for (const m in spelers) if (spelers[m] === st.naam) { weg = m; delete spelers[m]; }
    return publiceer(weg ? ("Ontkoppeld: " + st.naam + " (" + weg + ")") : (st.naam + " had geen baken."));
}
return null;

// Herstel spelersLijst bij (her)start uit het retained config/spelers (wint van de flows.json-seed).
if (msg.payload && typeof msg.payload === "object" && Object.keys(msg.payload).length) {
    global.set("spelersLijst", msg.payload);
}
return null;

if (!msg.payload || !msg.payload.mac) return null;
let K = global.get("beaconKalibratie") || {};
K[msg.payload.mac] = Number(msg.payload.offset) || 0;
global.set("beaconKalibratie", K);
return null;

const loc = global.get("spelerLocaties") || {};
const spel = global.get("pofHuidigSpel") || null;
return [
  { topic: "locatie/spelers", payload: loc },
  { topic: "spel/historie", payload: spel ? { actief: true, start: spel.start, events: spel.events.slice(-40) } : { actief: false, events: [] } }
];

const hist = global.get("spelHistorie") || [];
const fmt = (iso) => { try { return new Date(iso).toLocaleString("nl-BE"); } catch(e){ return iso; } };
msg.payload = hist.map(s => ({
  id: s.id,
  start: fmt(s.start),
  spelNummer: s.spelNummer || null,
  doel: s.doel || null,
  doelBereikt: s.doelBereikt || [],
  aantal: s.events.length,
  events: s.events.map(e => ({ nr: e.nr, tekst: e.tekst, doelwit: e.doelwit || [], getalWaarde: e.getalWaarde }))
}));
return msg;

if (msg.delete && Array.isArray(msg.delete)) {
    const weg = new Set(msg.delete.map(Number));
    let hist = global.get("spelHistorie") || [];
    hist = hist.filter(s => !weg.has(s.id));
    global.set("spelHistorie", hist);
}
return msg;

if (global.get("rssiDiagAan") !== true) { msg.payload = []; return msg; }
const nu = Date.now();
const VENSTER = 6000;
const buf = global.get("beaconBuf") || {};
const spelers = global.get("spelersLijst") || {};
let rows = [];
for (const mac in buf) {
    const per = {};
    for (const s of buf[mac]) {
        if (nu - s.ts > VENSTER) continue;
        (per[s.paal] = per[s.paal] || []).push(s.rssi);
    }
    const naam = spelers[mac] || "(onbekend)";
    for (const paal in per) {
        const arr = per[paal];
        rows.push({ Beacon: naam, Paal: Number(paal), Laatste: arr[arr.length-1], Min: Math.min(...arr), Max: Math.max(...arr), n: arr.length });
    }
}
rows.sort((a,b) => a.Beacon.localeCompare(b.Beacon) || b.Laatste - a.Laatste);
msg.payload = rows;
return msg;

const sim24 = msg.payload && msg.payload.sim24 === true;
global.set("simVeld24", sim24);
const palen = sim24 ? Array.from({length:24},(_,i)=>i+1) : (global.get("paaltjesLijst")||[]);
global.set("palenActief", palen);
// Forceer een volledige LED-hersync: de simulator kleurt zijn ring enkel uit niet-retained,
// diff-only commando-berichten, dus een (her)verbindende sim mist actieve toestand-LEDs
// (portaal/happy hour/medicijn/middernacht). paalLedForceRebuild laat 'Sync toestanden + LEDs'
// de hele ring opnieuw versturen, in lijn met de retained pof/toestanden-panelen.
global.set("paalLedForceRebuild", true);
return { payload: "sync" };

// Systeeminstellingen vanuit de simulator: toestand-exclusiviteit (tijdbom/ziekte niet samen)
// en de tempo/reactietijd-multiplier. Retained, dus komt ook binnen bij (her)verbinden.
const c = msg.payload || {};
if (c.toestandExclusief !== undefined) global.set("toestandExclusief", c.toestandExclusief !== false);
if (c.tempo !== undefined) { const t = Number(c.tempo); if (!isNaN(t) && t > 0) global.set("tempoFactor", t); }
if (c.settleGrace !== undefined) { const g = Number(c.settleGrace); if (!isNaN(g) && g >= 0) global.set("pofSettleGrace", g); }
if (c.dichtheid !== undefined) { const dd = Number(c.dichtheid); if (dd > 0 && dd <= 1) global.set("doelwitDichtheid", dd); }
return null;

// Doelwit-dichtheid-knob. topic "dichtheid" = slider (%); topic "init" = toon de opgeslagen waarde.
const cur = () => { const v = Number(global.get("doelwitDichtheid")); return (v > 0 && v <= 1) ? v : 0.25; };
if (msg.topic === "init") {
    return [ { payload: Math.round(cur() * 100) }, { payload: "Doelwit-dichtheid: " + Math.round(cur() * 100) + "%" } ];
}
const p = Number(msg.payload);
if (!isNaN(p)) {
    const d = Math.min(0.6, Math.max(0.05, p / 100));
    global.set("doelwitDichtheid", d);
    return [ null, { payload: "Doelwit-dichtheid: " + Math.round(d * 100) + "%" } ];
}
return null;

// Reactietijd-toestanden-basis (s). topic 'toestandreactie' = slider; topic 'init' = toon+zet default.
const cur = () => { const v = Number(global.get("reactieToestand")); return (v > 0) ? v : 10; };
if (msg.topic === "init") {
    global.set("reactieToestand", cur());
    return [ { payload: cur() }, { payload: "Reactietijd toestanden: " + cur() + "s" } ];
}
const p = Number(msg.payload);
if (!isNaN(p)) {
    const s = Math.min(30, Math.max(3, Math.round(p)));
    global.set("reactieToestand", s);
    return [ null, { payload: "Reactietijd toestanden: " + s + "s" } ];
}
return null;

// Een aankomend event uit de wachtrij weghalen (simulator-knop). De rij schuift door: de
// timer-tick van 'Bouw pof/status' vult ze daarna vanzelf weer aan tot 5.
let w = global.get("pofWachtrij") || [];
const i = (msg.payload || {}).index;
if (typeof i === "number" && i >= 0 && i < w.length) { w.splice(i, 1); global.set("pofWachtrij", w); }
return null;

// Spelinstellingen vanuit de simulator: 'slechte aura' aan/uit (negatieve speler-events treffen
// 's avonds/'s nachts vaker) en de 'thuisbank' (levensuren storten bij landen op je startuur).
// Retained, dus komt ook binnen bij (her)verbinden.
const c = msg.payload || {};
if (c.badAura !== undefined) global.set("badAuraAan", c.badAura !== false);
if (c.thuisbank !== undefined) global.set("thuisbankAan", c.thuisbank === true);
return null;

// Event-tier-overrides vanuit de simulator (events-tab). {id: tier}. Retained.
const c = (msg.payload && typeof msg.payload === "object") ? msg.payload : {};
global.set("eventTiers", c);
return null;

// Eén ronde terug in de tijd: herstel de laatste snapshot (gemaakt bij het begin van 'Kies event').
// Herpubliceert de afgeleide states + de speler-posities (pof/herstel-posities) en forceert een LED-rebuild.
let stack = global.get("pofSnapshots") || [];
if (!stack.length) { node.warn("Tijd terug: geen snapshot beschikbaar"); return null; }
const snap = stack.pop(); global.set("pofSnapshots", stack);
for (const k in snap) global.set(k, snap[k]);
global.set("pofFase", "wacht"); global.set("pofTeller", 0);
// De simulator zet de spelers zo dadelijk terug op hun oude paal: die programmatische hops mogen
// niet als 'vrij gewandeld' (V10) aangerekend worden -> register wissen + korte genade-drempel.
global.set("pofVrijPad", {}); global.set("pofVrijVanaf", Date.now() + 5000);
global.set("paalLedForceRebuild", true);
const loc = global.get("spelerLocaties") || {};
const ziek = global.get("ziekeSpelers") || {};
const ziekLijst = Object.keys(ziek).map(n => ({ speler:n, rondesOver: ziek[n], uur: loc[n] != null ? loc[n] : null }));
const bommen = global.get("tijdbomSpelers") || {};
const bomLijst = Object.keys(bommen).map(n => ({ speler:n, rondesOver: bommen[n], uur: loc[n] != null ? loc[n] : null }));
const ontmantel = global.get("tijdbomOntmantelPalen") || [];
const bord = global.get("bordStaat") || {}; const toestanden = [];
for (const u in bord) for (const e of (bord[u].effecten||[])) toestanden.push({ uur: parseInt(u,10), effect: e.effect, naam: e.naam, resterendeRondes: e.resterendeRondes });
const herstel = {}; for (const n in loc) herstel[n] = loc[n];
return [
  [
    { topic:"pof/ziekte", payload: ziekLijst, retain:true },
    { topic:"pof/tijdbom", payload: { spelers: bomLijst, ontmantelPalen: ontmantel }, retain:true },
    { topic:"pof/toestanden", payload: toestanden, retain:false },
    { topic:"pof/dienaars", payload: global.get("dienaars") || {}, retain:true },
    { topic:"pof/herstel-posities", payload: herstel, retain:false }
  ],
  { payload: "rebuild" }
];

const arr = (msg.payload && Array.isArray(msg.payload.uitgesloten)) ? msg.payload.uitgesloten : [];
global.set("uitgeslotenEvents", arr);
return null;

// Verwerk sim/bediening: programmatische engine-besturing voor het AI-testharnas.
// Werkt ENKEL in sim-modus (simVeld24===true) zodat een echt spel nooit geraakt wordt.
// out1 -> Spel aan/uit (start/stop) | out2 -> Sla pofManueel op (bool) | out3 -> Engine tick (pof_volgende/pof_controle) | out4 -> Wis globale stats
