const status = { topic: "pof/doelstatus", payload: { doel: doel, percent: percent, aantal: geslaagd.length, totaal: totaal, spelers: bereikt } };
let stop = null;
const lopend = (global.get("spelToestand") || "gestopt") === "lopend";
const auto = global.get("pofAutoEinde") === true;
const nodig = global.get("pofDoelAantal") || 1;
if (lopend && auto && doel.type !== "geen" && geslaagd.length >= nodig) stop = { payload: "uit" };
return [status, stop];

const t = global.get("spelToestand") || "gestopt";
msg.payload = (t === "gepauzeerd") ? "\u23f8 PAUZE" : (t === "lopend") ? "\u25b6 Loopt" : "\u23f9 Gestopt";
return msg;

// Dashboard-keuze monitor/simulatie -> publiceer sim/modus (retained). "Sim-veld instellen"
// (mqtt-in sim/modus) zet daarna global.simVeld24 + palenActief. Browser-sim volgt ook mee.
return { topic: "sim/modus", payload: { sim24: msg.payload === true } };

// Toon de Doel-groep enkel in Plates of Fate; verberg bij Klokslag.
const pof = (global.get("spelType") || "plates_of_fate") === "plates_of_fate";
return { payload: { group: pof ? { show: ["d8a0000000000040"] } : { hide: ["d8a0000000000040"] } } };

const d = msg.payload || {};
msg.payload = (d.doel && d.doel.type && d.doel.type !== "geen")
  ? ("Doel bereikt: " + (d.aantal || 0) + "/" + (d.totaal || 0) + " (" + (d.percent || 0) + "%)")
  : "Geen doel actief";
return msg;

// Een event ACHTERAAN in de wachtrij zetten (simulator-knop op een event-kaart). De rij schuift
// door: capt op 5; 'Bouw pof/status' filtert niet-kiesbare ids en vult daarna weer aan tot 5.
let w = global.get("pofWachtrij") || [];
const id = (msg.payload || {}).id;
if (id) { w = w.filter(x => x !== id); w.push(id); if (w.length > 5) w = w.slice(w.length - 5); global.set("pofWachtrij", w); }
return null;

// Audio-test: speel spelernaam-WAV('s) af op de box via audio/afspelen.
// Gebruikt DEZELFDE normalisatie als "Kies doelwit" zodat dit exact test wat het spel speelt.
function veilig(s){return String(s).normalize("NFD").replace(/[̀-ͯ]/g,"").toLowerCase().replace(/[^a-z0-9]+/g,"_").replace(/^_+|_+$/g,"");}
const p = msg.payload;
let segs, tekst;
if (msg.topic === "test_alle" || p === "ALLE") {
    const lijst = global.get("spelersLijst") || {};
    let namen = Object.values(lijst);
    if (!namen.length) namen = ["Lilou","Zoë","Louisa","Lola","Maud","Mien"];
    segs = ["doelwit/voor.wav"].concat(namen.map(n => "spelers/" + veilig(n) + ".wav")).concat(["doelwit/na.wav"]);
    tekst = "Alle spelers: " + namen.join(", ");
} else {
    segs = ["spelers/" + veilig(p) + ".wav"];
    tekst = String(p);
}
return { payload: { fase: "audio-test", tekst: tekst, segments: segs, prioriteit: "normaal" } };

// Arm/disarm een drukknop-paal: stuurt ACTIE_KNOP_ARM(17)/UIT(18) naar de slave + bewaart de stand.
const armed = global.get("knopTestArmed") || {};
const paal = parseInt(msg.topic, 10);
let cmd = null;
if (!isNaN(paal)) {
    const aan = (msg.payload === true || msg.payload === "true");
    armed[paal] = aan;
    global.set("knopTestArmed", armed);
    cmd = { payload: { paal: paal, actie: aan ? 17 : 18 } };
}
return [cmd, { refresh: true }];

// Toon de cumulatieve druk-teller van de slave (zetten, niet optellen -> verloren berichten zelf-corrigerend).
const d = msg.payload || {};
const paal = d.paal;
if (paal == null) return null;
const counts = global.get("knopTestCounts") || {};
counts[paal] = (d.teller != null) ? d.teller : ((counts[paal] || 0) + 1);
global.set("knopTestCounts", counts);
return msg;

// Reset: alle drukknop-palen inactief (LED uit), tellers + stand wissen, schakelaars visueel uit.
const palen = global.get("drukknopPalen") || [];
global.set("knopTestArmed", {});
global.set("knopTestCounts", {});
const cmds = palen.map(p => ({ payload: { paal: p, actie: 18 } }));
return [cmds.length ? cmds : null, { refresh: true }, { payload: false }];

// Bouw de drukknop-test-tabel: per geconfigureerde paal of hij actief is + de telling.
const palen = global.get("drukknopPalen") || [];
const armed = global.get("knopTestArmed") || {};
const counts = global.get("knopTestCounts") || {};
msg.payload = palen.map(p => ({ Paal: p, Actief: armed[p] ? "✅ actief" : "—", Tellingen: counts[p] || 0 }));
return msg;

// Huidig spel: valsspeelpunten, opgebouwde slechte-aura% en god-punten-saldo per speler.
const spelers = global.get("spelersLijst") || {};
const stats = global.get("spelerStats") || {};
let rows = [];
for (const mac in spelers) {
    const n = spelers[mac];
    const s = stats[n] || {};
    rows.push({ Speler: n, Valsspeelpunten: s.valsspeelpunten || 0, "Aura%": (s.auraValsspeel || 0) + "%", "God-punten": s.godPunten || 0 });
}
if (!rows.length) rows = [{ Speler: "-", Valsspeelpunten: 0, "Aura%": "0%", "God-punten": 0 }];
msg.payload = rows;
return msg;

// === Infected minigame-engine + LED + status. Eigen spelmodus (global.spelType === "infected").
// Gevoed door de 250ms-tick. out1-3: commando/master1-3 (effen rood/blauw per paal via MSG_KLOKSLAG, actie 16).
// out4: infected/status (retained) -> dashboard + simulator. Timers via Date.now(): besmetting 15s, bestrijders 60s.
const lopend = (global.get("spelToestand") || "gestopt") === "lopend";
const isInf = (global.get("spelType") || "plates_of_fate") === "infected";

function ledOff(palen) { const a=[],b=[],c=[]; for (const p of palen) { const m={payload:{paal:p,actie:16,r:0,g:0,b:0,helderheid:0,modus:3}}; if(p<=8)a.push(m); else if(p<=16)b.push(m); else c.push(m); } return [a,b,c]; }

if (!isInf || !lopend) {
    if (global.get("infectedActief")) {
        global.set("infectedActief", false);
        const uit = ledOff((global.get("infectedLaatstePalen") || []));
        global.set("infectedLed", {}); global.set("infectedLaatstePalen", []); global.set("infectedStatusSig", "");
        return [uit[0].length?uit[0]:null, uit[1].length?uit[1]:null, uit[2].length?uit[2]:null, { payload: { actief:false, fase:"gestopt", besmet:[], overlevenden:[], bestrijders:[], winnaars:[], aantalBesmet:0, aantalOver:0, bestrijderResterend:0, palen:{} } }];
    }
    return null;
}

const now = Date.now();
const loc = global.get("spelerLocaties") || {};
const _gp = global.get("gespauzeerdePlayers") || {};
const actief = Object.keys(loc).filter(n => _gp[n] !== true);   // gepauzeerd telt niet mee (S1)

let inf = global.get("infected");
if (!global.get("infectedActief") || !inf) {
    if (!actief.length) return null;   // wacht tot er spelers op het veld staan
    const p0 = actief[Math.floor(Math.random() * actief.length)];
    inf = { besmet: [p0], bestrijders: [], bestrijderTot: 0, dwell: {}, fase: "lopend", winnaars: [], start: now, startAantal: actief.length };
    global.set("infected", inf); global.set("infectedLed", {}); global.set("infectedActief", true); global.set("infectedStatusSig", "");
}

function bouwStatus(o, palen) {
    return { actief:true, fase: inf.fase, besmet: inf.besmet.slice(), overlevenden: o.slice(),
        bestrijders: inf.bestrijders.slice(), winnaars: inf.winnaars.slice(),
        aantalBesmet: inf.besmet.length, aantalOver: o.length,
        bestrijderResterend: inf.bestrijderTot ? Math.max(0, Math.round((inf.bestrijderTot - now)/1000)) : 0,
        palen: palen || {} };
}
function emit(o1,o2,o3,statusObj) {
    const sig = JSON.stringify(statusObj);
    let sm = null;
    if (sig !== global.get("infectedStatusSig")) { global.set("infectedStatusSig", sig); sm = { payload: statusObj }; }
    return [o1&&o1.length?o1:null, o2&&o2.length?o2:null, o3&&o3.length?o3:null, sm];
}

if (inf.fase === "klaar") { return emit(null,null,null, bouwStatus(inf.winnaars, {})); }

const besmetSet = new Set(inf.besmet);
const perPaal = {};
for (const n of actief) { const p = loc[n]; (perPaal[p] = perPaal[p] || []).push(n); }
let over = actief.filter(n => !besmetSet.has(n));

// Bestrijder-rotatie: vanaf 5 besmet -> 2 bestrijders, elke 60s nieuwe (liefst andere).
if (inf.besmet.length >= 5) {
    if (!inf.bestrijders.length || now >= inf.bestrijderTot) {
        const huidig = new Set(inf.bestrijders);
        let kand = over.filter(n => !huidig.has(n));
        if (kand.length < 2) kand = over.slice();
        for (let i=kand.length-1;i>0;i--){const j=Math.floor(Math.random()*(i+1));const t=kand[i];kand[i]=kand[j];kand[j]=t;}
        inf.bestrijders = kand.slice(0,2); inf.bestrijderTot = now + 60000;
    }
} else { inf.bestrijders = []; inf.bestrijderTot = 0; }
const bestrSet = new Set(inf.bestrijders);
const veiligePalen = new Set();
for (const n of inf.bestrijders) { if (loc[n] != null) veiligePalen.add(loc[n]); }

// Besmetting: niet-besmette/niet-bestrijder die >=15s op een paal met een besmette (en niet-veilig) staat -> besmet.
for (const n of over) {
    if (bestrSet.has(n)) { delete inf.dwell[n]; continue; }
    const p = loc[n];
    if (veiligePalen.has(p)) { delete inf.dwell[n]; continue; }
    const besmetHier = (perPaal[p] || []).some(m => besmetSet.has(m));
    if (!besmetHier) { delete inf.dwell[n]; continue; }
    if (!inf.dwell[n]) inf.dwell[n] = now;
    if (now - inf.dwell[n] >= (5000 + Math.floor(inf.besmet.length / 2) * 1000)) { inf.besmet.push(n); besmetSet.add(n); delete inf.dwell[n]; }
}
over = actief.filter(n => !besmetSet.has(n));

// Win: laatste 3 overblijvenden (enkel in een echt spel: meer dan 3 starters + minstens 1 besmet).
if (inf.startAantal > 3 && inf.besmet.length > 0 && over.length <= 3) {
    inf.fase = "klaar"; inf.winnaars = over.slice(); inf.bestrijders = []; inf.bestrijderTot = 0;
}

// LED per paal: bestrijder -> blauw, anders besmette -> rood, anders uit. Alleen bij wijziging (cache).
const RED=[224,36,36], BLUE=[30,111,255];
const kleur = {};
for (const p in perPaal) { const pp=parseInt(p,10); const occ=perPaal[p];
    if (occ.some(m => bestrSet.has(m))) kleur[pp] = "blauw";
    else if (occ.some(m => besmetSet.has(m))) kleur[pp] = "rood"; }
const cache = global.get("infectedLed") || {};
const consider = new Set();
for (const k in kleur) consider.add(parseInt(k,10));
for (const k in cache) consider.add(parseInt(k,10));
const o1=[],o2=[],o3=[]; const push=(m)=>{const p=m.payload.paal; if(p<=8)o1.push(m); else if(p<=16)o2.push(m); else o3.push(m);};
for (const p of consider) {
    const kl = kleur[p] || null; let key, c;
    if (kl === "blauw") { key="b"; c=BLUE; } else if (kl === "rood") { key="r"; c=RED; } else { key="x"; }
    if (cache[p] === key) continue;
    if (key === "x") { delete cache[p]; push({payload:{paal:p,actie:16,r:0,g:0,b:0,helderheid:0,modus:3}}); }
    else { cache[p]=key; push({payload:{paal:p,actie:16,r:c[0],g:c[1],b:c[2],helderheid:255,modus:0}}); }
}
global.set("infectedLed", cache);
global.set("infectedLaatstePalen", Object.keys(cache).map(Number));
global.set("infected", inf);
return emit(o1,o2,o3, bouwStatus(over, kleur));

// Bouw de infected-statustabel uit infected/status (gevoed door de engine).
const s = msg.payload || {};
const j = (a) => (a && a.length) ? a.join(", ") : "—";
const fMap = { lopend: "Loopt", klaar: "Afgelopen — winnaars!", gestopt: "Gestopt" };
let rows = [
    { Veld: "Fase", Waarde: fMapNaam(s.fase) },
    { Veld: "Besmet (" + (s.aantalBesmet || 0) + ")", Waarde: j(s.besmet) },
    { Veld: "Overlevenden (" + (s.aantalOver || 0) + ")", Waarde: j(s.overlevenden) },
    { Veld: "Bestrijders", Waarde: j(s.bestrijders) + (s.bestrijderResterend ? "  (" + s.bestrijderResterend + "s)" : "") },
    { Veld: "Winnaars", Waarde: j(s.winnaars) }
];
function fMapNaam(f){ return ({ lopend: "Loopt", klaar: "Afgelopen — winnaars!", gestopt: "Gestopt" })[f] || (f || "—"); }
msg.payload = rows;
return msg;

// L7: dag/avond locatie-presets. actie = topic (laad|bewaar), profiel = payload (dag|avond).
const actie = msg.topic;
const profiel = (msg.payload === "avond") ? "avond" : "dag";
let presets = global.get("locPresets") || {};
const overdrive = global.get("overdriveActief") === true;
const basis = Object.assign({}, overdrive ? (global.get("locParamsNormaal") || {}) : (global.get("locParams") || {}));
const uit = [null, null, null, null, null, null, null];

if (actie === "bewaar") {
    presets[profiel] = {
        vensterMs: basis.vensterMs, hystereseDbm: basis.hystereseDbm, rssiVloer: basis.rssiVloer,
        graceMs: basis.graceMs, switchSamples: basis.switchSamples, minSamples: basis.minSamples
    };
    global.set("locPresets", presets);
    uit[6] = { payload: "Bewaard -> " + profiel };
    return uit;
}

// actie === "laad"
const p = presets[profiel];
if (!p) { uit[6] = { payload: "Geen preset: " + profiel }; return uit; }
global.set("locProfiel", profiel);
global.set("locParamsNormaal", Object.assign({}, p));
if (overdrive) {
    global.set("locParams", Object.assign({}, p, { vensterMs: 2500, graceMs: 1500 }));
    uit[6] = { payload: "Actief profiel: " + profiel + " (overdrive actief)" };
    return uit;
}
global.set("locParams", Object.assign({}, p));
uit[0] = { payload: p.vensterMs };
uit[1] = { payload: p.hystereseDbm };
uit[2] = { payload: p.rssiVloer };
uit[3] = { payload: p.graceMs };
uit[4] = { payload: p.switchSamples };
uit[5] = { payload: p.minSamples };
uit[6] = { payload: "Actief profiel: " + profiel };
return uit;

// Avondspel-modus vanuit de simulator (retained). true = avondspel, false = middagspel.
const c = msg.payload || {};
if (c.avond !== undefined) global.set("avondModus", c.avond === true);
return null;

// Onmiddellijke dood: loterij (gewicht = sterftes + valsspeelpunten) + cirkelende paarsrode LED + kill.
// Stop-veilig via pofGeneration. out1 = pof/dood-anim (sim), out2 = audio/afspelen, out3 = Route commando (hardware).
const myGen = global.get("pofGeneration") || 0;
const loc = global.get("spelerLocaties") || {};
const gp = global.get("gespauzeerdePlayers") || {};
let stats = global.get("spelerStats") || {};
const ring = (global.get("palenActief") || global.get("paaltjesLijst") || []).slice().sort((a, b) => a - b);
if (!ring.length) { node.warn("Onmiddellijke dood: geen palen"); return null; }
let kand = Object.keys(loc).filter(n => !gp[n] && !((stats[n] || {}).gestorven));
if (!kand.length) { node.warn("Onmiddellijke dood: geen kandidaten"); return null; }

// Loterij: gewicht = sterftes + valsspeelpunten. 0 = immuun; is alles 0 -> uniform.
const gew = (n) => ((stats[n] || {}).sterftes || 0) + ((stats[n] || {}).valsspeelpunten || 0);
const tot = kand.reduce((s, n) => s + gew(n), 0);
let slachtoffer;
if (tot <= 0) { slachtoffer = kand[Math.floor(Math.random() * kand.length)]; }
else { let r = Math.random() * tot; slachtoffer = kand.find(n => (r -= gew(n)) < 0) || kand[kand.length - 1]; }
const doelPaal = loc[slachtoffer];

// Hardware (flood-vermijdend): oogst-strobe op alle palen tijdens de animatie (smooth cirkel = sim-only).
node.send([null, null, ring.map(u => ({ payload: { paal: u, actie: 11 } }))]);

// Cirkel-animatie: cursor loopt ~2 rondjes rond de ring, vertraagt (ease-out) en stopt op doelPaal.
const eindIdx = Math.max(0, ring.indexOf(doelPaal));
const stappen = 2 * ring.length + eindIdx;
let t = 0;
for (let i = 0; i <= stappen; i++) {
    const paal = ring[i % ring.length];
    const laatste = (i === stappen);
    const frac = stappen ? i / stappen : 1;
    t += 60 + Math.round(440 * frac * frac);
    setTimeout(() => {
        if ((global.get("pofGeneration") || 0) !== myGen) return;   // Stop/reset -> afbreken
        node.send([{ topic: "pof/dood-anim", payload: { fase: laatste ? "gekozen" : "loopt", paal: paal, speler: laatste ? slachtoffer : null } }, null, null]);
        if (laatste) {
            let s2 = global.get("spelerStats") || {};
            let sv = s2[slachtoffer] || {}; if (sv.totaalUren === undefined) sv.totaalUren = 0; if (sv.sterftes === undefined) sv.sterftes = 0;
            sv.totaalUren = 0; sv.sterftes += 1; sv.gestorven = true; s2[slachtoffer] = sv;
            global.set("spelerStats", s2);
            const veilig = String(slachtoffer || "").toLowerCase().normalize("NFD").replace(/[^a-z0-9]+/g, "_");
            node.send([null, { payload: { fase: "doelwit", tekst: slachtoffer + " sterft.", segments: ["doelwit/voor.wav", "spelers/" + veilig + ".wav", "doelwit/na.wav"], prioriteit: "hoog" } }, ring.map(u => ({ payload: { paal: u, actie: 0 } }))]);
            global.set("paalLedForceRebuild", true);
            node.warn("Onmiddellijke dood: " + slachtoffer + " (gewicht " + gew(slachtoffer) + ") is gestorven.");
        }
    }, t);
}
return null;
